"""Artificial Analysis API client with local caching."""
import json
import os
import time
from typing import Dict, List, Optional
from pathlib import Path
from urllib.request import Request, urlopen
from urllib.error import URLError, HTTPError

_API_BASE = "https://artificialanalysis.ai/api/v2"
_CACHE_DIR = Path(__file__).parent.parent / "data" / "cache"
_CACHE_FILE = _CACHE_DIR / "llm_models.json"
_DEFAULT_TTL = 24 * 3600


def _get_api_key() -> str:
    try:
        from tool.ARTIFICIAL_ANALYSIS.logic import _config_key
        return _config_key()
    except Exception:
        pass
    cfg_path = Path(__file__).parent.parent / "tool.json"
    if cfg_path.exists():
        try:
            return json.loads(cfg_path.read_text()).get("config", {}).get("api_key", "")
        except Exception:
            pass
    return os.environ.get("ARTIFICIAL_ANALYSIS_API_KEY", "")


def _load_cache() -> Optional[dict]:
    if _CACHE_FILE.exists():
        try:
            data = json.loads(_CACHE_FILE.read_text())
            age = time.time() - data.get("_cached_at", 0)
            if age < _DEFAULT_TTL:
                return data
        except Exception:
            pass
    return None


def _save_cache(data: dict):
    _CACHE_DIR.mkdir(parents=True, exist_ok=True)
    data["_cached_at"] = time.time()
    _CACHE_FILE.write_text(json.dumps(data, ensure_ascii=False, indent=2))


def fetch_llm_models(force_refresh: bool = False, api_key: str = "") -> dict:
    """Fetch LLM model data from Artificial Analysis API.

    Returns dict with 'data' list of model objects.
    """
    if not force_refresh:
        cached = _load_cache()
        if cached:
            return cached

    key = api_key or _get_api_key()
    if not key:
        return {"error": "No API key configured. Set it in tool.json or ARTIFICIAL_ANALYSIS_API_KEY env var."}

    url = f"{_API_BASE}/data/llms/models"
    req = Request(url, headers={"x-api-key": key, "Accept": "application/json"})
    try:
        with urlopen(req, timeout=30) as resp:
            data = json.loads(resp.read().decode("utf-8"))
        _save_cache(data)
        return data
    except HTTPError as e:
        return {"error": f"HTTP {e.code}: {e.reason}"}
    except URLError as e:
        return {"error": f"Network error: {e.reason}"}
    except Exception as e:
        return {"error": str(e)}


